--
-- Table structure for table `blueprints`
--

DROP TABLE IF EXISTS `blueprints`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `blueprints` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(200) COLLATE utf8mb4_general_ci NOT NULL,
  `description` text COLLATE utf8mb4_general_ci,
  `base_price` decimal(12,2) NOT NULL DEFAULT '0.00',
  `wood_type` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `creator_id` int NOT NULL,
  `client_id` int DEFAULT NULL,
  `assigned_staff_id` int DEFAULT NULL,
  `assign_task_type` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `stage` enum('design','estimation','approval','production','delivery','completed','archived') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'design',
  `design_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `view_3d_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `locked_fields` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `thumbnail_url` mediumtext COLLATE utf8mb4_general_ci,
  `source` enum('created','imported') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'created',
  `file_url` text COLLATE utf8mb4_general_ci,
  `file_type` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `is_template` tinyint(1) NOT NULL DEFAULT '0',
  `is_gallery` tinyint(1) NOT NULL DEFAULT '0',
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  `archived_at` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `creator_id` (`creator_id`),
  KEY `client_id` (`client_id`),
  KEY `assigned_staff_id` (`assigned_staff_id`),
  CONSTRAINT `blueprints_ibfk_1` FOREIGN KEY (`creator_id`) REFERENCES `users` (`id`),
  CONSTRAINT `blueprints_ibfk_2` FOREIGN KEY (`client_id`) REFERENCES `users` (`id`),
  CONSTRAINT `blueprints_ibfk_3` FOREIGN KEY (`assigned_staff_id`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `blueprints_chk_1` CHECK (json_valid(`design_data`)),
  CONSTRAINT `blueprints_chk_2` CHECK (json_valid(`view_3d_data`)),
  CONSTRAINT `blueprints_chk_3` CHECK (json_valid(`locked_fields`))
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

