INSERT INTO `contracts` VALUES (1,2,2,40,'Rica Aguam','2026-04-24',NULL,'1. SCOPE OF WORK\nThe contractor agrees to fabricate and deliver the custom woodwork as described in the approved blueprint and cost estimation attached to this contract.\n\n2. PAYMENT TERMS\nA down payment of 30% of the total contract price is required before fabrication begins. The remaining balance is due upon delivery and acceptance of the finished product.\n\n3. DELIVERY & INSTALLATION\nThe estimated completion and delivery date will be agreed upon after the down payment is received. Delays caused by customer changes or force majeure will extend the timeline accordingly.\n\n4. CHANGES & REVISIONS\nAny changes to the approved design after fabrication has begun may incur additional charges and timeline adjustments, subject to mutual agreement.\n\n5. OWNERSHIP\nOwnership of the finished product transfers to the customer upon full payment of the contract price.\n\n6. GOVERNING LAW\nThis contract shall be governed by the laws of the Republic of the Philippines.','This product is covered by a one (1) year warranty from the date of delivery against defects in materials and workmanship under normal use conditions.\n\nWarranty does not cover damage caused by misuse, neglect, unauthorized modifications, or external causes such as accidents or natural disasters.\n\nTo file a warranty claim, contact Spiral Wood Services with proof of purchase and documentation of the defect.',0.00,15.00,0,1,NULL,NULL,'2026-04-24 03:42:09','2026-04-24 03:42:09'),(2,3,5,40,'Rica Aguam','2026-04-25',NULL,'1. SCOPE OF WORK\nThe contractor agrees to fabricate and deliver the custom woodwork as described in the approved blueprint and cost estimation attached to this contract.\n\n2. PAYMENT TERMS\nA down payment of 30% of the total contract price is required before fabrication begins. The remaining balance is due upon delivery and acceptance of the finished product.\n\n3. DELIVERY & INSTALLATION\nThe estimated completion and delivery date will be agreed upon after the down payment is received. Delays caused by customer changes or force majeure will extend the timeline accordingly.\n\n4. CHANGES & REVISIONS\nAny changes to the approved design after fabrication has begun may incur additional charges and timeline adjustments, subject to mutual agreement.\n\n5. OWNERSHIP\nOwnership of the finished product transfers to the customer upon full payment of the contract price.\n\n6. GOVERNING LAW\nThis contract shall be governed by the laws of the Republic of the Philippines.','This product is covered by a one (1) year warranty from the date of delivery against defects in materials and workmanship under normal use conditions.\n\nWarranty does not cover damage caused by misuse, neglect, unauthorized modifications, or external causes such as accidents or natural disasters.\n\nTo file a warranty claim, contact Spiral Wood Services with proof of purchase and documentation of the defect.',0.00,15.00,0,1,NULL,NULL,'2026-04-25 10:29:19','2026-04-25 10:29:19'),(3,5,7,40,'Rica Aguam','2026-04-29',NULL,'1. SCOPE OF WORK\nThe contractor agrees to fabricate and deliver the custom woodwork as described in the approved blueprint and cost estimation attached to this contract.\n\n2. PAYMENT TERMS\nA down payment of 30% of the total contract price is required before fabrication begins. The remaining balance is due upon delivery and acceptance of the finished product.\n\n3. DELIVERY & INSTALLATION\nThe estimated completion and delivery date will be agreed upon after the down payment is received. Delays caused by customer changes or force majeure will extend the timeline accordingly.\n\n4. CHANGES & REVISIONS\nAny changes to the approved design after fabrication has begun may incur additional charges and timeline adjustments, subject to mutual agreement.\n\n5. OWNERSHIP\nOwnership of the finished product transfers to the customer upon full payment of the contract price.\n\n6. GOVERNING LAW\nThis contract shall be governed by the laws of the Republic of the Philippines.','This product is covered by a one (1) year warranty from the date of delivery against defects in materials and workmanship under normal use conditions.\n\nWarranty does not cover damage caused by misuse, neglect, unauthorized modifications, or external causes such as accidents or natural disasters.\n\nTo file a warranty claim, contact Spiral Wood Services with proof of purchase and documentation of the defect.',0.00,15.00,0,1,NULL,NULL,'2026-04-29 07:13:22','2026-04-29 07:13:22');
