INSERT INTO `products` (`id`, `barcode`, `name`, `description`, `category_id`, `type`, `image_url`, `is_featured`, `online_price`, `walkin_price`, `production_cost`, `stock`, `reorder_point`, `stock_status`, `is_published`, `blueprint_id`, `created_at`, `updated_at`) VALUES (46,'CHR-0001','Modern Wooden Dining Chair','Modern wooden dining chair with cushioned seat and curved backrest. Ideal for dining areas, cafes, and minimalist interiors. Made with durable wood frame and upholstered fabric seat for comfort and everyday use.',1,'standard','/uploads/products/1776512699272-1406owzlvgod.png',1,4500.00,4300.00,2800.00,37,2,'in_stock',1,NULL,'2026-04-18 11:45:00','2026-04-22 06:56:05'),(47,'BED-0001','Nordic Wooden Platform Bed','Modern wooden platform bed with clean lines, sturdy frame, and minimalist headboard design. Ideal for contemporary bedroom interiors and built for everyday comfort and durability.',1,'standard','/uploads/products/1776512794020-8vps473ug45.png',1,18500.00,17800.00,11800.00,20,5,'in_stock',1,NULL,'2026-04-18 11:46:34','2026-04-18 11:46:34'),(48,'TAB-0001','Modern Wooden Coffee Table','Modern wooden coffee table with open lower shelf and minimalist rectangular design. Ideal for living rooms and lounge spaces, offering both surface space and practical storage for books or decor.',5,'standard','/uploads/products/1776512889894-daimxxvp5np.png',1,6800.00,6500.00,4200.00,49,5,'in_stock',1,NULL,'2026-04-18 11:48:10','2026-04-21 13:00:02'),(50,'TVC-0001','Modern Wooden TV Console','Modern wooden TV console with spacious side compartments and open center shelving. Designed for living rooms and entertainment spaces, offering practical storage for media devices, decor, and everyday essentials',5,'standard','/uploads/products/1776513132661-fajzcc7z6h4.png',1,9800.00,9400.00,6200.00,49,6,'in_stock',1,NULL,'2026-04-18 11:52:13','2026-04-21 13:00:02'),(51,'DSK-0001','Modern Wooden Office Desk','Modern wooden office desk with spacious tabletop, built-in drawer storage, and a clean professional design. Ideal for home offices, study areas, and workspaces, offering both functionality and durability for daily use.',4,'standard','/uploads/products/1776513250694-9uzsx6dv9em.png',1,11500.00,10900.00,7200.00,49,5,'in_stock',1,NULL,'2026-04-18 11:54:11','2026-04-21 13:00:02'),(52,'WRD-0001','Modern Wooden Wardrobe Cabinet','Modern wooden wardrobe cabinet with spacious hanging sections, drawer storage, and open shelving. Designed for bedrooms, it provides organized storage for clothes, accessories, and essentials while adding a clean and elegant wood finish to the space.',1,'standard','/uploads/products/1776513356674-3pmdrvqavpp.png',1,24500.00,23600.00,15800.00,50,5,'in_stock',1,NULL,'2026-04-18 11:55:57','2026-04-18 11:55:57'),(53,'CLS-0001','Modern Wooden Closet Wardrobe','Modern wooden closet wardrobe with hanging space, multiple drawers, upper cabinets, and open shelving. Designed for bedrooms, it provides organized storage for clothes, bags, and daily essentials while giving the room a clean and elegant wood finish.',1,'standard','/uploads/products/1776513521318-bqt8ukryrg.png',1,26800.00,25900.00,17200.00,49,5,'in_stock',1,NULL,'2026-04-18 11:58:42','2026-04-21 13:00:02'),(54,'VNY-0001','Modern Wooden Bathroom Vanity','Modern wooden bathroom vanity with built-in sink, spacious drawer storage, and a clean contemporary design. Ideal for bathroom interiors, offering organized storage for essentials while adding a warm and elegant wood finish.',1,'standard','/uploads/products/1776513704981-ewri8bsvdcd.png',1,15800.00,14900.00,9800.00,46,5,'in_stock',1,NULL,'2026-04-18 12:01:45','2026-04-22 09:30:39'),(55,'MRC-0001','Modern Wooden Bathroom Mirror Cabinet','Modern wooden bathroom mirror cabinet with integrated shelving, spacious mirror panels, and a clean contemporary design. Ideal for organizing bathroom essentials while adding practical storage and an elegant wood finish to the space.',1,'standard','/uploads/products/1776513778774-7kgcde4fqyx.png',1,13800.00,13200.00,8599.99,0,6,'out_of_stock',1,NULL,'2026-04-18 12:02:59','2026-04-18 14:38:24'),(58,'KTN-STD-001','Modular L-Shaped Kitchen Cabinet','Modern modular L-shaped kitchen cabinet with upper and lower storage cabinets, wood-finish panels, built-in countertop layout, and clean contemporary design. Ideal for residential kitchen spaces.',2,'standard','/uploads/products/1776527693869-jxqh7xrd8m.png',1,68500.00,65000.00,48000.00,50,5,'in_stock',1,NULL,'2026-04-18 15:54:55','2026-04-21 12:59:24'),(66,'LIV-TVC-001','Wooden TV Console Cabinet','Low-profile wooden TV console with sliding side panels, open center shelves, and modern storage space for television units, media devices, and home décor.',5,'standard','/uploads/products/1776533736333-8y902qkrtjl.png',1,16500.00,15200.00,10300.00,100,10,'in_stock',1,NULL,'2026-04-18 17:35:37','2026-04-18 17:35:37'),(69,'OFF-DSK-001','Solid Wood Study Desk','Solid wood study desk with wide tabletop, side drawers, and a clean minimalist design, ideal for home office, study, and workspace use.',4,'standard','/uploads/products/1776534055397-b7mn3ftbsvu.png',1,18900.00,17500.00,12100.00,100,10,'in_stock',1,NULL,'2026-04-18 17:40:56','2026-04-18 17:40:56'),(70,'STR-CAB-001','Wooden Storage Cabinet with Drawers','Functional wooden storage cabinet with multiple drawers and double-door compartment, ideal for organizing household items in living, dining, or bedroom spaces.',8,'standard','/uploads/products/1776534567456-dshj4he6hu.png',1,17900.00,16500.00,11400.00,1099,15,'in_stock',1,NULL,'2026-04-18 17:49:28','2026-04-22 03:13:12'),(71,'DIN-CHR-001','Cushioned Wooden Dining Chair','Wooden dining chair with cushioned upholstered seat and supportive backrest, designed for comfort, durability, and a refined dining room setup.',6,'standard','/uploads/products/1776534706070-8rr8kdjefat.png',1,4200.00,3900.00,2400.00,0,5,'out_of_stock',0,NULL,'2026-04-18 17:51:47','2026-04-24 12:48:21'),(72,'LIV-SDT-001','Wooden Side Table with Shelf','Compact wooden side table with open shelf storage, ideal for placement beside sofas, lounge chairs, or beds in modern home interiors.',5,'standard','/uploads/products/1776534821585-xngqdejla7m.png',1,5200.00,4800.00,3100.00,50,7,'in_stock',1,NULL,'2026-04-18 17:53:42','2026-04-18 17:53:42'),(73,'LIV-CFT-001','Wooden Coffee Table with Open Shelf','Minimalist wooden coffee table with spacious tabletop and open lower shelf, ideal for books, décor, and everyday living room essentials.',5,'standard','/uploads/products/1776534934747-91ssy0fn9s6.png',1,8900.00,8200.00,5400.00,10,5,'in_stock',1,NULL,'2026-04-18 17:55:36','2026-04-18 17:55:36'),(74,'BED-STD-001','Wooden Platform Bed Frame','Solid wood platform bed frame with wide headboard, durable structure, and clean modern design, ideal for warm and minimalist bedroom interiors.',1,'standard','/uploads/products/1776535049296-vth81e7r9ep.png',1,32900.00,30900.00,22400.00,100,10,'in_stock',1,NULL,'2026-04-18 17:57:30','2026-04-18 17:57:30'),(75,'DIN-SET-001','6-Seater Wooden Dining Set','Elegant 6-seater wooden dining set with rectangular table and matching cushioned chairs, ideal for family dining, entertaining guests, and modern dining interiors.',6,'standard','/uploads/products/1776535168812-r51a1d0f6vq.png',1,45900.00,43500.00,30800.00,45,10,'in_stock',1,NULL,'2026-04-18 17:59:30','2026-07-09 07:57:32'),(76,'DIN-TBL-001','Rectangular Wooden Dining Table','Large rectangular wooden dining table with sturdy pedestal-style base and warm natural wood finish, ideal for family dining spaces and modern home interiors.',6,'standard','/uploads/products/1776535311376-c9a74m2nmh7.png',1,24900.00,23200.00,16100.00,99,10,'in_stock',1,NULL,'2026-04-18 18:01:52','2026-04-23 12:56:30'),(77,'WWC-001','Modern Walk-In Wardrobe Closet','A modern modular wardrobe and closet unit designed for organized clothing storage. Features open hanging sections, upper storage compartments, drawers, shelves, and lower shoe storage. Ideal for bedrooms and walk-in closet spaces, with a warm wood finish and clean contemporary look. Bagay ito sa WISDOM / Spiral Wood product direction dahil ang business ninyo ay naka-focus sa modular cabinets and closets.',7,'standard','/uploads/products/1776536232649-vhgs9xzczd.png',1,28500.00,27500.00,19000.00,92,10,'in_stock',1,NULL,'2026-04-18 18:17:14','2026-04-24 02:01:38'),(78,'BTH-VNT-001','Modern Bathroom Vanity Cabinet','Modern bathroom vanity cabinet with integrated sink counter, base storage, side drawers, mirror cabinet, and warm wood finish, ideal for organized and stylish bathroom interiors.qw21232131123',3,'standard','/uploads/products/1776536499156-l8veuznqafm.png',0,28900.00,26900.00,18600.00,90,10,'in_stock',1,NULL,'2026-04-18 18:21:40','2026-07-09 03:41:30'),(97,'BP-1777112680698','Closet','Custom 3D designed product.',2,'blueprint',NULL,0,30130.00,30130.00,0.00,999,0,'in_stock',1,1,'2026-04-25 10:24:57','2026-04-25 10:24:57'),(98,'BP-1777446263918','Table','Custom 3D designed product.',2,'blueprint',NULL,0,10976.00,10976.00,0.00,999,0,'in_stock',1,4,'2026-04-29 07:04:24','2026-04-29 07:04:24');
